/**
 * Generate HTML/CSS to Image firewall config.
 *
 * Data source: https://docs.htmlcsstoimage.com/getting-started/authentication
 *
 * HTML/CSS to Image uses HTTP Basic Auth with user_id as username and api_key as password.
 */

import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://docs.htmlcsstoimage.com/getting-started/authentication";
// UUID-shaped placeholder using c0ffee5afe10ca1 vocabulary (see README.md)
const PLACEHOLDER_VALUE = "c0ffee5a-fe10-ca1c-0ffe-e5afe10ca1c0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from HTML/CSS to Image API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:htmlcsstoimage",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const htmlcsstoimageFirewall = {",
    '  name: "htmlcsstoimage",',
    '  description: "HTML/CSS to Image API",',
    "  placeholders: {",
    `    HCTI_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://hcti.io",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "${{ basic(vars.HCTI_USER_ID, secrets.HCTI_API_KEY) }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating HTML/CSS to Image firewall config...");
  const ts = generateTypeScript();
  writeOutput("htmlcsstoimage", ts, import.meta.dirname);
}
